parameters.jsCode:
// ============================================================
// JIRA HIGH TICKET CREATION — EMAIL NOTIFICATION
// Same design system as daily briefing & weekly report
// Triggered: on high/highest priority issue creation
// ============================================================

const issue  = $input.first().json.issue;
const fields = issue.fields || {};

// ── Safe helpers ──────────────────────────────────────────────
const s   = (v, f = '') => (v != null ? String(v) : f);
const esc = (v) => String(v ?? '')
  .replace(/&/g, '&amp;').replace(/</g, '&lt;')
  .replace(/>/g, '&gt;').replace(/"/g, '&quot;');

// ── Design tokens (identical to report system) ────────────────
const BRAND     = '#0F3D6E';
const BRAND_ACC = '#0052CC';
const SURFACE   = '#FFFFFF';
const SURFACE2  = '#F4F5F7';
const BORDER    = '#DFE1E6';
const TEXT1     = '#172B4D';
const TEXT2     = '#5E6C84';
const TEXT3     = '#8993A4';

const JIRA_BASE = $input.first().json.JIRA_DOMAIN + "/browse";

// ── Issue fields ──────────────────────────────────────────────
const issueKey    = s(issue.key);
const summary     = s(fields.summary);
const project     = s(fields.project?.name);
const issueType   = s(fields.issuetype?.name, 'Issue');
const priority    = s(fields.priority?.name,  'Not set');
const status      = s(fields.status?.name,    'To Do');
const reporter    = s(fields.reporter?.displayName, 'Unknown');
const assignee    = s(fields.assignee?.displayName, 'Unassigned');
const description = s(fields.description, '');
const created     = fields.created
  ? new Date(fields.created).toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })
  : '';

const issueUrl = `${JIRA_BASE}/${issueKey}`;

// ── Priority colours ──────────────────────────────────────────
const priorityMap = {
  'Highest': { bg: '#FFEBE6', text: '#BF2600', border: '#BF2600', dot: '#BF2600', label: 'HIGHEST' },
  'High':    { bg: '#FFEBE6', text: '#BF2600', border: '#FF5630', dot: '#FF5630', label: 'HIGH'    },
  'Medium':  { bg: '#FFFAE6', text: '#FF8B00', border: '#FF8B00', dot: '#FF8B00', label: 'MEDIUM'  },
  'Low':     { bg: '#E3FCEF', text: '#006644', border: '#36B37E', dot: '#36B37E', label: 'LOW'     },
  'Lowest':  { bg: '#F4F5F7', text: '#5E6C84', border: '#8993A4', dot: '#8993A4', label: 'LOWEST'  },
};
const pc = priorityMap[priority] || priorityMap['Medium'];

// ── Status colours ────────────────────────────────────────────
const statusMap = {
  'To Do':       { bg: '#F4F5F7', text: '#42526E' },
  'In Progress': { bg: '#DEEBFF', text: '#0052CC' },
  'In Review':   { bg: '#EAE6FF', text: '#6554C0' },
  'Done':        { bg: '#E3FCEF', text: '#006644' },
  'Blocked':     { bg: '#FFEBE6', text: '#BF2600' },
};
const sc = statusMap[status] || { bg: SURFACE2, text: TEXT2 };

// ── Issue type colours ────────────────────────────────────────
const typeMap = {
  'Bug':     { bg: '#FFEBE6', text: '#BF2600' },
  'Feature': { bg: '#EEF4FF', text: '#0052CC' },
  'Story':   { bg: '#E3FCEF', text: '#006644' },
  'Task':    { bg: '#F4F5F7', text: '#42526E' },
  'Epic':    { bg: '#EAE6FF', text: '#6554C0' },
};
const tc = typeMap[issueType] || { bg: SURFACE2, text: TEXT2 };

// ── Is this a highest/high urgency? ──────────────────────────
const isUrgent = priority === 'Highest' || priority === 'High';

// ── Meta row helper ───────────────────────────────────────────
const metaRow = (label, value, last = false) =>
  `<tr style="border-bottom:${last ? 'none' : '1px solid '+BORDER};">
    <td style="padding:10px 16px 10px 0;width:110px;vertical-align:top;">
      <div style="font-size:10px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.07em;">${label}</div>
    </td>
    <td style="padding:10px 0;vertical-align:top;">
      <div style="font-size:13px;color:${TEXT1};">${value}</div>
    </td>
  </tr>`;

// ── Pill badge ────────────────────────────────────────────────
const pill = (label, bg, text) =>
  `<span style="display:inline-block;background:${bg};color:${text};border-radius:3px;padding:2px 8px;font-size:11px;font-weight:700;letter-spacing:0.04em;">${esc(label)}</span>`;

// ════════════════════════════════════════════════════════════
// HEADER
// ════════════════════════════════════════════════════════════
const headerHtml = `
<tr><td style="background:${BRAND};border-radius:8px 8px 0 0;padding:24px 30px;">
  <table width="100%" cellpadding="0" cellspacing="0" border="0"><tr valign="top">

    <td style="padding-right:16px;">
      <div style="font-size:9px;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:rgba(255,255,255,0.4);margin-bottom:8px;">
        ${esc(project)} &nbsp;/&nbsp; New Issue Created
      </div>
      <div style="font-size:17px;font-weight:700;color:#FFFFFF;line-height:1.35;margin-bottom:8px;">
        ${esc(summary)}
      </div>
      <div style="font-size:11px;color:rgba(255,255,255,0.45);">${created ? `Created ${created}` : ''}</div>
    </td>

    <!-- Issue key badge -->
    <td style="width:140px;vertical-align:top;">
      <table width="140" cellpadding="0" cellspacing="0"
             style="background:rgba(255,255,255,0.11);border:1px solid rgba(255,255,255,0.15);border-radius:6px;">
      <tr><td style="padding:12px 14px;text-align:center;">
        <div style="font-size:9px;font-weight:700;letter-spacing:0.09em;color:rgba(255,255,255,0.4);text-transform:uppercase;margin-bottom:6px;">Issue Key</div>
        <div style="font-size:18px;font-weight:700;color:#FFFFFF;margin-bottom:10px;">${esc(issueKey)}</div>
        <div style="background:${pc.bg};border-radius:20px;padding:3px 10px;white-space:nowrap;display:inline-block;">
          <span style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:0.07em;color:${pc.text};white-space:nowrap;">● ${pc.label}</span>
        </div>
      </td></tr>
      </table>
    </td>

  </tr></table>
</td></tr>`;

// ════════════════════════════════════════════════════════════
// URGENT ALERT BANNER (High / Highest only)
// ════════════════════════════════════════════════════════════
const alertBanner = isUrgent ? `
<tr><td style="background:#FFEBE6;border-left:4px solid #BF2600;border-right:1px solid ${BORDER};padding:11px 24px;">
  <table width="100%" cellpadding="0" cellspacing="0" border="0"><tr valign="middle">
    <td style="font-size:10px;font-weight:700;color:#BF2600;text-transform:uppercase;letter-spacing:0.07em;width:1%;white-space:nowrap;padding-right:12px;">🔴 High Priority Issue</td>
    <td style="font-size:11px;color:#7F2000;line-height:1.5;">
      This issue has been flagged as <strong>${esc(priority)}</strong> priority and requires prompt attention.
    </td>
  </tr></table>
</td></tr>` : '';

// ════════════════════════════════════════════════════════════
// QUICK STATS STRIP — 3 key facts at a glance
// ════════════════════════════════════════════════════════════
const statsStrip = `
<tr><td style="background:${SURFACE};border-left:1px solid ${BORDER};border-right:1px solid ${BORDER};border-top:1px solid ${BORDER};padding:14px 20px;">
  <table width="100%" cellpadding="0" cellspacing="0" border="0" style="table-layout:fixed;"><tr valign="middle">

    <td style="text-align:center;padding:6px 4px;border-right:1px solid ${BORDER};">
      <div style="margin-bottom:5px;">${pill(issueType, tc.bg, tc.text)}</div>
      <div style="font-size:9px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.06em;">Type</div>
    </td>

    <td style="text-align:center;padding:6px 4px;border-right:1px solid ${BORDER};">
      <div style="margin-bottom:5px;">${pill(priority, pc.bg, pc.text)}</div>
      <div style="font-size:9px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.06em;">Priority</div>
    </td>

    <td style="text-align:center;padding:6px 4px;">
      <div style="margin-bottom:5px;">${pill(status, sc.bg, sc.text)}</div>
      <div style="font-size:9px;font-weight:700;color:${TEXT3};text-transform:uppercase;letter-spacing:0.06em;">Status</div>
    </td>

  </tr></table>
</td></tr>`;

// ════════════════════════════════════════════════════════════
// ISSUE DETAILS — meta table
// ════════════════════════════════════════════════════════════
const detailsHtml = `
<tr><td style="background:${SURFACE};border-left:1px solid ${BORDER};border-right:1px solid ${BORDER};border-top:1px solid ${BORDER};padding:20px 30px;">
  <div style="border-bottom:1px solid ${BORDER};padding-bottom:10px;margin-bottom:16px;">
    <span style="font-size:13px;font-weight:700;color:${TEXT1};">Issue Details</span>
  </div>
  <table width="100%" cellpadding="0" cellspacing="0" border="0">
    ${metaRow('Issue',    `<a href="${esc(issueUrl)}" style="color:${BRAND_ACC};font-weight:700;text-decoration:none;">${esc(issueKey)}</a>`)}
    ${metaRow('Project',  esc(project))}
    ${metaRow('Type',     pill(issueType, tc.bg, tc.text))}
    ${metaRow('Priority', pill(priority,  pc.bg, pc.text))}
    ${metaRow('Status',   pill(status,    sc.bg, sc.text))}
    ${metaRow('Reporter', esc(reporter))}
    ${metaRow('Assignee', esc(assignee), !description)}
    ${description ? metaRow('Description', `<div style="font-size:12px;color:${TEXT2};line-height:1.7;">${esc(description)}</div>`, true) : ''}
  </table>
</td></tr>`;

// ════════════════════════════════════════════════════════════
// CTA — Open in Jira button
// ════════════════════════════════════════════════════════════
const ctaHtml = `
<tr><td style="background:${BRAND};border-left:1px solid ${BORDER};border-right:1px solid ${BORDER};border-top:1px solid ${BORDER};padding:16px 30px;">
  <table width="100%" cellpadding="0" cellspacing="0" border="0"><tr valign="middle">
    <td>
      <div style="font-size:12px;font-weight:700;color:#FFFFFF;margin-bottom:3px;">Review this issue in Jira</div>
      <div style="font-size:10px;color:rgba(255,255,255,0.5);">
        Assign, comment, update priority or start working on it directly.
      </div>
    </td>
    <td style="text-align:right;white-space:nowrap;padding-left:16px;">
      <a href="${esc(issueUrl)}" target="_blank"
         style="display:inline-block;background:rgba(255,255,255,0.15);border:1px solid rgba(255,255,255,0.3);border-radius:4px;padding:8px 18px;font-size:11px;font-weight:700;color:#FFFFFF;text-decoration:none;white-space:nowrap;">
        Open in Jira →
      </a>
    </td>
  </tr></table>
</td></tr>`;

// ════════════════════════════════════════════════════════════
// FOOTER
// ════════════════════════════════════════════════════════════
const footerHtml = `
<tr><td style="background:${SURFACE};border-left:1px solid ${BORDER};border-right:1px solid ${BORDER};padding-bottom:16px;"></td></tr>
<tr><td style="background:${BRAND};border-radius:0 0 8px 8px;padding:14px 30px;">
  <table width="100%" cellpadding="0" cellspacing="0" border="0"><tr>
    <td style="font-size:10px;color:rgba(255,255,255,0.4);">
      Auto-generated by n8n &nbsp;·&nbsp; Jira — IG Green Team
    </td>
    <td align="right" style="font-size:10px;color:rgba(255,255,255,0.3);white-space:nowrap;padding-left:8px;">
      Do not reply
    </td>
  </tr></table>
</td></tr>`;

// ════════════════════════════════════════════════════════════
// ASSEMBLE
// ════════════════════════════════════════════════════════════
const html = `<!DOCTYPE html>
<html lang="en" xmlns="http://www.w3.org/1999/xhtml">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1.0"/>
  <meta http-equiv="X-UA-Compatible" content="IE=edge"/>
  <title>New Issue: ${esc(issueKey)}</title>
</head>
<body style="margin:0;padding:0;background:#E4E8EF;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI','Helvetica Neue',Arial,sans-serif;">

  <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#E4E8EF;padding:28px 0;">
    <tr><td align="center">
      <table width="620" cellpadding="0" cellspacing="0" border="0" style="max-width:620px;width:100%;">

        ${headerHtml}
        ${alertBanner}
        ${statsStrip}
        ${detailsHtml}
        ${ctaHtml}
        ${footerHtml}

      </table>
    </td></tr>
  </table>

</body>
</html>`;

// ── Subject line ──────────────────────────────────────────────
const subjectPrefix = isUrgent ? `🔴 [${priority.toUpperCase()}]` : `📋 [${priority.toUpperCase()}]`;
const subject = `${subjectPrefix} ${issueKey} — ${summary}`;

return [{
  json: {
    html,
    subject,
    emailTo: $input.first().json.emailTo || '',
  }
}];
